const body = $input.first().json;
const msg = body.message || body.callback_query?.message;
const chatId = msg?.chat?.id || body.callback_query?.from?.id;
const isCallback = !!body.callback_query;
const callbackData = body.callback_query?.data || null;
const callbackQueryId = body.callback_query?.id || null;
const text = body.message?.text || null;
const video = body.message?.video || null;
const photo = body.message?.photo || null;
const messageId = msg?.message_id || null;
const startToken = text?.startsWith('/start ') ? text.slice(7).trim() : null;
const isStart = text === '/start' || !!startToken;

return [{ json: { chatId, isCallback, callbackData, callbackQueryId, text, video, photo: photo ? photo[photo.length - 1] : null, messageId, startToken, isStart } }];

const normalized = $('Code: Normalize Update').first().json;
const whoamiRaw = $input.first().json;
const whoamiStatus = $input.first().json.$response?.statusCode || 200;
const whoami = (whoamiStatus === 200 && whoamiRaw && !whoamiRaw.error) ? whoamiRaw : null;
return [{ json: { ...normalized, whoami, whoamiStatus } }];

const ctx = $('Code: Merge whoami').first().json;
const sessionRows = $input.all();
const sessionState = (sessionRows && sessionRows.length > 0 && sessionRows[0].json && sessionRows[0].json.state) ? sessionRows[0].json.state : {};
const state = (typeof sessionState === 'string') ? JSON.parse(sessionState) : (sessionState || {});

const { chatId, isCallback, callbackData, text, video, photo, startToken, isStart, whoami } = ctx;

let route;

if (!whoami || whoami.error || whoami.detail === 'Not found') {
  route = startToken ? 'unknown_with_token' : 'unknown_no_token';
} else if (state && state.flow) {
  route = 'active_flow';
} else if (isCallback) {
  const map = {
    clock_in: 'cmd_clock_in',
    clock_out: 'cmd_clock_out',
    accident_start: 'cmd_accident',
    vehicle_issue: 'cmd_vehicle_issue',
    update_details: 'cmd_update_details',
    attendance_csv: 'cmd_attendance_csv',
    my_vehicle: 'cmd_my_vehicle',
    admin_attendance: 'cmd_admin_attendance',
    admin_broadcast: 'cmd_admin_broadcast',
    admin_summary: 'cmd_admin_summary',
    admin_maintenance: 'cmd_admin_maintenance',
  };
  route = map[callbackData] || (whoami.role === 'admin' ? 'admin_main' : 'driver_main');
} else if (isStart) {
  route = whoami.role === 'admin' ? 'admin_main' : 'driver_main';
} else {
  route = whoami.role === 'admin' ? 'admin_main' : 'driver_main';
}

return [{ json: { ...ctx, sessionState: state, route } }];

const claimResult = $input.first().json;
const ctx = $('Switch: Main Router').first().json;
const status = claimResult.$response?.statusCode || 200;
const success = status >= 200 && status < 300;
return [{ json: { ...ctx, claimSuccess: success } }];

