const ctx = $('Switch: Main Router').item.json;
const vehicleResult = $input.first().json;
const vehicles = Array.isArray(vehicleResult) ? vehicleResult : (vehicleResult.items || [vehicleResult]);
const vehicle = vehicles[0];
if (!vehicle || !vehicle.vehicle_id) {
  return [{ json: { ...ctx, errorMsg: 'לא נמצא רכב משויך לחשבונך.' } }];
}
const now = new Date();
const israelOffset = 3 * 60;
const israelTime = new Date(now.getTime() + israelOffset * 60000);
const datetimeStr = israelTime.toISOString().replace('T', ' ').slice(0, 16);
return [{ json: { ...ctx, vehicleId: vehicle.vehicle_id, accidentDatetime: datetimeStr, hasVehicle: true } }];

const ctx = $input.first().json;
const state = ctx.sessionState || {};
const flow = state.flow || '';
const step = state.step || '';
const callbackData = ctx.callbackData || '';
const hasVideo = !!ctx.video;
const hasPhoto = !!ctx.photo;
const hasText = !!ctx.text;

let activeRoute = 'unknown_active';

if (flow === 'accident') {
  if (step === 'awaiting_safe' && callbackData === 'accident_safe') activeRoute = 'accident_safe';
  else if (step === 'awaiting_video' && hasVideo) activeRoute = 'accident_video';
  else if (step === 'awaiting_vehicle_clear' && callbackData === 'accident_road_clear') activeRoute = 'accident_road_clear';
  else if (step === 'awaiting_insurance_photo' && hasPhoto) activeRoute = 'accident_insurance_photo';
  else if (step === 'awaiting_driver_license_photo' && hasPhoto) activeRoute = 'accident_driver_license';
  else if (step === 'awaiting_car_license_photo' && hasPhoto) activeRoute = 'accident_car_license';
  else if (step === 'awaiting_manager_call' && callbackData === 'accident_manager_called') activeRoute = 'accident_complete';
  else activeRoute = 'accident_wait';
} else if (flow === 'broadcast') {
  if (step === 'awaiting_message' && hasText) activeRoute = 'broadcast_message';
  else if (step === 'awaiting_confirm' && callbackData === 'broadcast_confirm') activeRoute = 'broadcast_confirm';
  else if (step === 'awaiting_confirm' && callbackData === 'broadcast_cancel') activeRoute = 'broadcast_cancel';
  else activeRoute = 'broadcast_wait';
}

return [{ json: { ...ctx, activeRoute } }];

