const ctx = $('Switch: Active Flow Routes').item.json;
const adminsResult = $input.first().json;
const admins = Array.isArray(adminsResult) ? adminsResult : (adminsResult.items || []);
const now = new Date();
const israelOffset = 3 * 60;
const israelTime = new Date(now.getTime() + israelOffset * 60000);
const datetimeStr = israelTime.toISOString().replace('T', ' ').slice(0, 16);
const driverName = ctx.whoami?.full_name || ctx.whoami?.name || 'לא ידוע';
const notifications = admins.filter(a => a.telegram_chat_id).map(a => ({
  chat_id: a.telegram_chat_id,
  text: `🚨 דיווח תאונה חדש\n\nנהג: ${driverName}\nזמן: ${datetimeStr}`,
  parse_mode: 'HTML'
}));
return notifications.map(n => ({ json: { notification: n, token: process.env.TELEGRAM_BOT_TOKEN } }));

const ctx = $('Switch: Main Router').item.json;
const rows = $input.all().map(i => i.json);
let lines = ['👥 נוכחות היום\n━━━━━━━━━━━━━━━━'];
if (rows.length === 0) {
  lines.push('אין נתוני נוכחות להיום.');
} else {
  rows.forEach(r => {
    const clockIn = r.clock_in || '--:--';
    const clockOut = r.clock_out || null;
    const indicator = clockOut ? '✅' : '⏳';
    const outStr = clockOut ? ` - ${clockOut}` : '';
    lines.push(`${indicator} ${r.full_name}: ${clockIn}${outStr}`);
  });
}
return [{ json: { ...ctx, attendanceText: lines.join('\n') } }];

const ctx = $('Switch: Main Router').item.json;
const kpi = $input.first().json;
const activeDrivers = kpi.active_drivers ?? kpi.drivers_clocked_in ?? 'N/A';
const activeVehicles = kpi.active_vehicles ?? kpi.vehicles_in_use ?? 'N/A';
const text = `🚗 סיכום צי\n━━━━━━━━━━━━━━━━\n\nנהגים מחוברים: ${activeDrivers}\nרכבים פעילים: ${activeVehicles}`;
return [{ json: { ...ctx, summaryText: text } }];

const ctx = $('Switch: Active Flow Routes').item.json;
const driversResult = $input.first().json;
const drivers = Array.isArray(driversResult) ? driversResult : (driversResult.items || []);
const withChat = drivers.filter(d => d.telegram_chat_id);
const count = withChat.length;
const broadcastMsg = ctx.text;
return [{ json: { ...ctx, broadcastMsg, driverCount: count, drivers: withChat } }];

const ctx = $('Switch: Active Flow Routes').item.json;
const state = ctx.sessionState || {};
const broadcastMsg = state.message || '';
const drivers = state.drivers || [];
return drivers.filter(d => d.telegram_chat_id).map(d => ({ json: { chatId: ctx.chatId, recipientChatId: d.telegram_chat_id, broadcastMsg } }));
